import { useState } from "react";

import {
  AppBar,
  Toolbar,
  Typography,
  Box,
  Button,
  Container,
  Paper,
  TextField,
} from "@mui/material";

import "./CreatePage.css";

function CreatePage() {

  const [category, setCategory] = useState("");
  const [openCategory, setOpenCategory] = useState(false);

  const [place, setPlace] = useState("");
  const [openPlace, setOpenPlace] = useState(false);

  const categoryList = [
    "노트북",
    "태블릿",
    "휴대폰",
    "에어팟/이어폰",
    "충전기",
    "학생증",
    "지갑",
    "가방",
    "필통",
    "전공책",
    "텀블러",
    "우산",
    "기타",
  ];

  const placeList = [
    "화도관 경비실",
    "비마관 경비실",
    "새빛관 경비실",
    "참빛관 경비실",
    "복지관 경비실",
    "한울관 경비실",
    "연구관 경비실",
    "문화관 경비실",
    "누리관 경비실",
    "80주년 기념관 경비실",
    "옥의관 경비실",
  ];

  return (
    <>
      {/* Navbar */}
      <AppBar position="static" className="navbar">
        <Toolbar className="navbar-toolbar">
          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />
        </Toolbar>
      </AppBar>

      {/* 배너 */}
      <Box className="create-header">

        <Typography variant="h4" className="create-title">
          유실물 등록
        </Typography>

        <Typography className="create-subtitle">
          유실물 정보를 입력해주세요
        </Typography>

      </Box>

      {/* 폼 */}
      <Container maxWidth="md">

        <Paper className="create-paper">

          {/* 이미지 */}
          <Button
            variant="contained"
            component="label"
            className="upload-button"
          >
            이미지 업로드
            <input hidden type="file" />
          </Button>

          {/* 습득 장소 */}
          <TextField
            fullWidth
            label="습득 장소"
            margin="normal"
          />

          {/* =========================
              습득 일자 (label 고정 해결)
          ========================= */}
          <TextField
            fullWidth
            type="date"
            margin="normal"
            label="습득일자"
            InputLabelProps={{
              shrink: true,   // 👈 항상 위에 고정
            }}
          />

          {/* =========================
              물품 분류 (커스텀 드롭다운)
          ========================= */}
          <Box sx={{ position: "relative", mt: 2 }}>

            <TextField
              fullWidth
              label="물품 분류"
              value={category}
              onClick={() => setOpenCategory(!openCategory)}
              InputProps={{ readOnly: true }}
            />

            {openCategory && (
              <Paper sx={{
                position: "absolute",
                width: "100%",
                zIndex: 10,
                maxHeight: 250,
                overflowY: "auto",
                mt: 0.5,
              }}>
                {categoryList.map((item) => (
                  <Box
                    key={item}
                    onClick={() => {
                      setCategory(item);
                      setOpenCategory(false);
                    }}
                    sx={{
                      padding: 2,
                      cursor: "pointer",
                      "&:hover": { backgroundColor: "#e3f2fd" },
                    }}
                  >
                    {item}
                  </Box>
                ))}
              </Paper>
            )}

          </Box>

          {/* 기타 입력 */}
          {category === "기타" && (
            <TextField
              fullWidth
              label="직접 입력"
              margin="normal"
            />
          )}

          {/* =========================
              보관 장소 (카테고리화)
          ========================= */}
          <Box sx={{ position: "relative", mt: 2 }}>

            <TextField
              fullWidth
              label="보관 장소"
              value={place}
              onClick={() => setOpenPlace(!openPlace)}
              InputProps={{ readOnly: true }}
            />

            {openPlace && (
              <Paper sx={{
                position: "absolute",
                width: "100%",
                zIndex: 10,
                maxHeight: 250,
                overflowY: "auto",
                mt: 0.5,
              }}>
                {placeList.map((item) => (
                  <Box
                    key={item}
                    onClick={() => {
                      setPlace(item);
                      setOpenPlace(false);
                    }}
                    sx={{
                      padding: 2,
                      cursor: "pointer",
                      "&:hover": { backgroundColor: "#e3f2fd" },
                    }}
                  >
                    {item}
                  </Box>
                ))}
              </Paper>
            )}

          </Box>

          {/* 상세 정보 */}
          <TextField
            fullWidth
            multiline
            rows={5}
            label="물건 상세 정보"
            margin="normal"
          />

          {/* 등록 버튼 */}
          <Button
            fullWidth
            variant="contained"
            className="submit-button"
          >
            게시물 등록
          </Button>

        </Paper>

      </Container>
    </>
  );
}

export default CreatePage;
